3522 /// Check whether the KnownBits of a select arm may be affected by the
3523 /// select condition.
3524 static bool hasAffectedValue(Value *V, SmallPtrSetImpl<Value *> &Affected,
3525                              unsigned Depth) {
3526   if (Depth == MaxAnalysisRecursionDepth)
3527     return false;
3528 
3529   // Ignore the case where the select arm itself is affected. These cases
3530   // are handled more efficiently by other optimizations.
3531   if (Depth != 0 && Affected.contains(V))
3532     return true;
3533 
3534   if (auto *I = dyn_cast<Instruction>(V)) {
3535     if (isa<PHINode>(I)) {
3536       if (Depth == MaxAnalysisRecursionDepth - 1)
3537         return false;
3538       Depth = MaxAnalysisRecursionDepth - 2;
3539     }
3540     return any_of(I->operands(), [&](Value *Op) {
3541       return Op->getType()->isIntOrIntVectorTy() &&
3542              hasAffectedValue(Op, Affected, Depth + 1);
3543     });
3544   }
3545 
3546   return false;
3547 }
